		const gridBox = await this.page.locator('ag-grid-angular').boundingBox();
		expect(gridBox?.height ?? 0).toBeGreaterThan(300);
	}

	async filterBySampleName(name: string): Promise<void> {
		await this.page.getByLabel('Sample Filter Input').fill(name);
	}

	async expectSampleVisible(name: string): Promise<void> {
		await expect(this.page.getByText(name)).toBeVisible({ timeout: 60_000 });
	}

	async createSample(sampleName: string): Promise<void> {
		await this.page.getByRole('button', { name: /New Sample/i }).click();
		await expect(this.page.getByRole('heading', { name: /New Sample/i })).toBeVisible();

