		await expect(this.page.locator('mat-dialog-container')).toHaveCount(0, {
			timeout: 60_000,
		});
	}

	async selectFirstVisibleRow(): Promise<void> {
		await this.page.locator('.ag-row input[type="checkbox"]').first().check({
			force: true,
		});
	}

	async openSelectedSample(): Promise<void> {
		await this.page.getByRole('button', { name: 'Open', exact: true }).click();
