import type { Page } from '@playwright/test';
import { expect } from '@playwright/test';
import { ROUTES } from '../utils/urls';

export class SampleTrackingPage {
	constructor(private readonly page: Page) {}

	async goto(): Promise<void> {
		await this.page.goto(ROUTES.sampleTracking);
	}

	async expectLoaded(): Promise<void> {
		await expect(this.page.getByText('Sample Tracking')).toBeVisible({
			timeout: 60_000,
		});
		await expect(this.page.locator('ag-grid-angular')).toBeVisible();
	}

	async expectGridRendered(): Promise<void> {
		await expect.poll(async () => {
			return this.page.locator('.ag-row').count();
		}, { timeout: 60_000 }).toBeGreaterThan(0);

		const gridBox = await this.page.locator('ag-grid-angular').boundingBox();
		expect(gridBox?.height ?? 0).toBeGreaterThan(300);
	}

	async filterBySampleName(name: string): Promise<void> {
		await this.page.getByLabel('Sample Filter Input').fill(name);
	}

	async expectSampleVisible(name: string): Promise<void> {
		await expect(this.page.getByText(name)).toBeVisible({ timeout: 60_000 });
	}

	async createSample(sampleName: string): Promise<void> {
		await this.page.getByRole('button', { name: /New Sample/i }).click();
		await expect(this.page.getByRole('heading', { name: /New Sample/i })).toBeVisible();

		await this.page.locator('mat-dialog-container input').nth(0).fill(sampleName);
		await this.page.locator('mat-dialog-container input[type="number"]').nth(0).fill('1');
		await this.selectDialogOption(4, 'NYC');
		await this.page.locator('mat-dialog-container textarea').fill(
			'Automated E2E sample. Safe to delete.',
		);

		await this.page.getByRole('button', { name: /^Create$/ }).click();
		await expect(this.page.locator('mat-dialog-container')).toHaveCount(0, {
			timeout: 60_000,
		});
	}

	async selectFirstVisibleRow(): Promise<void> {
		await this.page.locator('.ag-row input[type="checkbox"]').first().check({
			force: true,
		});
	}

	async openSelectedSample(): Promise<void> {
		await this.page.getByRole('button', { name: 'Open', exact: true }).click();
		await expect(this.page.locator('mat-dialog-container')).toBeVisible();
	}

	async expectDetailTabs(): Promise<void> {
		for (const tab of ['Info', 'Photos', 'Comments', 'Timeline']) {
			await expect(this.page.getByRole('tab', { name: tab })).toBeVisible();
		}
	}

	async addComment(comment: string): Promise<void> {
		await this.page.getByRole('tab', { name: 'Comments' }).click();
		await this.page.locator('mat-dialog-container textarea').fill(comment);
		await this.page.getByRole('button', { name: 'Post' }).click();
		await expect(this.page.getByText(comment)).toBeVisible({ timeout: 60_000 });
	}

	private async selectDialogOption(selectIndex: number, optionText: string): Promise<void> {
		await this.page
			.locator('mat-dialog-container mat-select .mat-mdc-select-trigger')
			.nth(selectIndex)
			.click({ force: true });
		await this.page.getByRole('option', { name: optionText, exact: true }).click();
	}
}

